import React, { useState, useEffect } from 'react';
import './App.css';

const ZipIcon = () => <span>📦</span>;

function App() {
  const [curtainOpen, setCurtainOpen] = useState(false);
  const [logoFade, setLogoFade] = useState(false);
  const [activeTab, setActiveTab] = useState('home');
  const [isUnzipped, setIsUnzipped] = useState(false);

  const YEARS_EXP = 15;

  useEffect(() => {
    const timer1 = setTimeout(() => {
      setLogoFade(true);
    }, 1500);

    const timer2 = setTimeout(() => {
      setCurtainOpen(true);
    }, 2200);

    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
    };
  }, []);

  return (
    <div className="app-container">
      {/* 1. CURTAIN OPENING ANIMATION OVERLAY */}
      <div className="curtain-container">
        <div className={`curtain-panel left ${curtainOpen ? 'open' : ''}`} />
        <div className={`curtain-panel right ${curtainOpen ? 'open' : ''}`} />
        <div className={`curtain-logo-wrapper ${logoFade ? 'fade-out' : ''}`}>
          <div className="logo-badge">
            <h1 className="gold-text">LX</h1>
          </div>
          <h2 className="gold-text">LUXURY ENTERPRISE</h2>
          <p style={{ color: '#aaa', marginTop: '5px' }}>{YEARS_EXP} Years of Excellence</p>
        </div>
      </div>

      {/* 2. HEADER NAVBAR */}
      <header className="navbar">
        <div className="brand-logo gold-text" style={{ fontSize: '1.5rem', fontWeight: 'bold' }}>
          LUXURY & CO.
        </div>
        <ul className="nav-links">
          {['home', 'about', 'services', 'gallery', 'contact'].map((tab) => (
            <li 
              key={tab} 
              className={activeTab === tab ? 'active' : ''}
              onClick={() => setActiveTab(tab)}
            >
              {tab.toUpperCase()}
            </li>
          ))}
        </ul>
      </header>

      {/* 3. DYNAMIC PAGE CONTENT */}
      <main className="page-wrapper">
        {activeTab === 'home' && <HomePage years={YEARS_EXP} setActiveTab={setActiveTab} />}
        {activeTab === 'about' && <AboutPage years={YEARS_EXP} />}
        {activeTab === 'services' && <ServicesPage />}
        {activeTab === 'gallery' && <GalleryPage isUnzipped={isUnzipped} setIsUnzipped={setIsUnzipped} />}
        {activeTab === 'contact' && <ContactPage />}
      </main>

      {/* 4. FOOTER */}
      <footer>
        <div className="footer-grid">
          <div>
            <h3 className="gold-text" style={{ marginBottom: '15px' }}>Luxury Enterprise</h3>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem', lineHeight: '1.6' }}>
              Crafting high-end experiences and bespoke solutions for over {YEARS_EXP} years. Quality and prestige defined.
            </p>
          </div>
          <div>
            <h4 className="gold-text" style={{ marginBottom: '15px' }}>Quick Links</h4>
            <ul style={{ listStyle: 'none', lineHeight: '2' }}>
              {['home', 'about', 'services', 'gallery', 'contact'].map((item) => (
